# Import necessary modules
import csv

def validate_csv_schema(file_path):
    # Open the CSV file and read its contents
    with open(file_path, mode='r', newline='') as csvfile:
        reader = csv.DictReader(csvfile)

        # Check if the 'age' column is present in the schema
        if 'age' not in reader.fieldnames:
            raise ValueError("The 'age' column is missing from the CSV file.")

        # Iterate over each row and check for age validation
        for row in reader:
            try:
                age = int(row['age'])
                if age < 0:
                    raise ValueError("Age cannot be negative.")
            except ValueError as e:
                print(f"Error: {e}")

    return True

# Example usage
file_path = 'example.csv'
if validate_csv_schema(file_path):
    print("CSV file is valid.")
else:
    print("CSV file is invalid.")
